// String to Number
let str = "123";
let num = Number(str);
console.log(num); // 予想される出力: 123

// Number to String
let num2 = 123;
let str2 = num2.toString();
console.log(str2); // 予想される出力: "123"

// Boolean to Number
let bool = true;
let num3 = Number(bool);
console.log(num3); // 予想される出力: 1

// Number to Boolean
let num4 = 0;
let bool2 = Boolean(num4);
console.log(bool2); // 予想される出力: false

// プリミティブ型
let num = 123;
console.log(typeof num); // 予想される出力: "number"

// オブジェクト型
let obj = {name: 'John', age: 30};
console.log(typeof obj); // 予想される出力: "object"
console.log(obj.name); // 予想される出力: "John"

// 数値と文字列の加算
let result = '3' + 2;
console.log(result); // 予想される出力: "32" // 文字列の"3"と数値の2が文字列の"32"に型変換される

// Truthyの例
let truthyValue = 'Hello';
if (truthyValue) {
  console.log('This value is truthy.'); // 予想される出力: "This value is truthy."
}

// Falsyの例
let falsyValue = 0;
if (!falsyValue) {
  console.log('This value is falsy.'); // 予想される出力: "This value is falsy."
}

// 配列の生成
let array = [1, 2, 3];
console.log(array); // 予想される出力: [1, 2, 3]

// オブジェクトの生成
let object = {key1: 'value1', key2: 'value2'};
console.log(object); // 予想される出力: {key1: 'value1', key2: 'value2'}

// プリミティブ型の生成
let primitive = 'Hello';
console.log(typeof primitive); // 予想される出力: "string"

// オブジェクト型の生成
let object = {greeting: 'Hello'};
console.log(typeof object); // 予想される出力: "object"

// 値型（プリミティブ型）の例
let value1 = 10;
let value2 = value1;
value1 = 20;
console.log(value2); // 予想される出力: 10

// 参照型（オブジェクト型）の例
let obj1 = {prop: 10};
let obj2 = obj1;
obj1.prop = 20;
console.log(obj2.prop); // 予想される出力: 20

// 関数を変数に代入する
let myFunction = function() {
    console.log('Hello, world!');
};
myFunction(); // 予想される出力: "Hello, world!"

// undefinedの例
let myUndefined;
console.log(myUndefined); // 予想される出力: undefined

// nullの例
let myNull = null;
console.log(myNull); // 予想される出力: null

// 型変換の例
let value1 = '5';
let value2 = 3;
let result = value1 + value2;
console.log(result); // 予想される出力: "53"

// 明示的な型変換
let convertedValue = Number(value1);
let result2 = convertedValue + value2;
console.log(result2); // 予想される出力: 8

// Falsyな値の例
let falsyValue = 0;
if (falsyValue) {
    console.log('This won't be logged.');
} else {
    console.log('Falsy value: ' + falsyValue); // 予想される出力: "Falsy value: 0"
}

// Truthyな値の例
let truthyValue = 'Hello';
if (truthyValue) {
    console.log('Truthy value: ' + truthyValue); // 予想される出力: "Truthy value: Hello"
}

// NaNの例
let result = 'Hello' / 2;
console.log(result); // 予想される出力: NaN

// undefinedの例
let undefinedValue;
console.log(undefinedValue); // 予想される出力: undefined

// nullの例
let nullValue = null;
console.log(nullValue); // 予想される出力: null

// Symbolの例
let symbol1 = Symbol('symbol1');
let symbol2 = Symbol('symbol1');

console.log(symbol1 === symbol2); // 予想される出力: false

// オブジェクトのプロパティキーとしてのSymbol
let obj = {};
obj[symbol1] = 'Hello';
console.log(obj[symbol1]); // 予想される出力: "Hello"

// typeof演算子の例
let number = 123;
console.log(typeof number); // 予想される出力: "number"

// instanceof演算子の例
let array = [1, 2, 3];
console.log(array instanceof Array); // 予想される出力: true

// データ型の変換例
let num = 123;
let str = num.toString();
console.log(str); // 予想される出力: "123"

let booleanValue = Boolean(str);
console.log(booleanValue); // 予想される出力: true

// 配列の作成と要素へのアクセス
let array = [1, 2, 3, 4, 5];
console.log(array[2]); // 予想される出力: 3

// 配列の例
let array = [1, 2, 3, 4, 5];
console.log(array[2]); // 予想される出力: 3

// オブジェクトの例
let object = {key1: 'value1', key2: 'value2'};
console.log(object.key1); // 予想される出力: "value1"

// pushとpopメソッドの例
let array = [1, 2, 3, 4, 5];

array.push(6);
console.log(array); // 予想される出力: [1, 2, 3, 4, 5, 6]

array.pop();
console.log(array); // 予想される出力: [1, 2, 3, 4, 5]
